CREATE OR REPLACE FUNCTION public.delete_auth_user_on_profile_delete()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
begin
  delete from auth.users where id = old.id;
  return old;
end;
$function$

CREATE OR REPLACE FUNCTION public.move_to_next_department()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  current_seq INT;
  next_dept TEXT;
  expected_hours NUMERIC;
  pk_now TIMESTAMP;
BEGIN
  pk_now := timezone('Asia/Karachi', now());

  IF NEW.status = 'completed' THEN

    SELECT step INTO current_seq
    FROM department_sequence
    WHERE department = NEW.department;

    SELECT department INTO next_dept
    FROM department_sequence
    WHERE step = current_seq + 1;

    IF next_dept IS NULL THEN
      UPDATE ordersmain
      SET status = 'completed'
      WHERE order_id = NEW.order_id;
    ELSE
      SELECT estimated_hours INTO expected_hours
      FROM master_time_config
      WHERE department = next_dept;

      INSERT INTO department_orders(
        order_id,
        department,
        expected_hours,
        status,
        date_in,
        time_in
      ) VALUES (
        NEW.order_id,
        next_dept,
        COALESCE(expected_hours,0),
        'inprogress',
        pk_now::date,
        pk_now::time
      );

      UPDATE ordersmain
      SET current_department = next_dept
      WHERE order_id = NEW.order_id;
    END IF;

    -- ✅ completion timestamps in PK
    UPDATE department_orders
    SET date_out = pk_now::date,
        time_out = pk_now::time
    WHERE id = NEW.id;

  END IF;

  RETURN NEW;
END;
$function$
